function LetterBadge({ letter, color }) {
  const len = letter?.length || 1;
  return (
    <div style={{
      width: 22, height: 22, borderRadius: 5, flexShrink: 0,
      background: color + "22", border: `1px solid ${color}66`,
      display: "flex", alignItems: "center", justifyContent: "center",
      fontFamily: "Space Mono", fontSize: len > 2 ? 7 : len > 1 ? 8 : 10,
      fontWeight: 700, color: color, letterSpacing: 0,
    }}>{letter}</div>
  );
}

function SmartIcon({ src, name, letter, color }) {
  const [failed, setFailed] = useState(false);
  if (failed) return <LetterBadge letter={letter || name?.slice(0,2).toUpperCase()} color={color} />;
  return <img src={src} alt={name} onError={() => setFailed(true)} style={{ width: 22, height: 22, objectFit: "contain" }} />;
}

